import{_ as e,e as t}from"./app.8ed067ad.js";const p={},o=t('<p>\u5DE5\u63A7\u7CFB\u7EDF\u4F5C\u4E3A\u5173\u952E\u57FA\u7840\u8BBE\u65BD\u4E0D\u53EF\u5206\u5272\u7684\u4E00\u90E8\u5206\uFF0C\u53EF\u7B80\u5316\u7535\u529B\u3001\u77F3\u6CB9\u5929\u7136\u6C14\u3001\u4F9B\u6C34\u3001\u4EA4\u901A\u53CA\u5316\u5DE5\u7B49\u91CD\u8981\u884C\u4E1A\u90E8\u95E8\u7684\u8FD0\u8425\u3002</p><p>\u65E5\u76CA\u589E\u957F\u7684\u7F51\u7EDC\u5B89\u5168\u95EE\u9898\u53CA\u5176\u5BF9\u5DE5\u63A7\u7CFB\u7EDF\u7684\u5F71\u54CD\u6108\u53D1\u51F8\u663E\u4E86\u5173\u952E\u57FA\u7840\u8BBE\u65BD\u6240\u9762\u4E34\u7684\u91CD\u5927\u98CE\u9669\u3002</p><p>\u89E3\u51B3\u5DE5\u63A7\u7CFB\u7EDF\u7684\u7F51\u7EDC\u5B89\u5168\u95EE\u9898\uFF0C\u987B\u5BF9\u5B89\u5168\u6311\u6218\u4E0E\u7279\u5B9A\u9632\u62A4\u63AA\u65BD\u6709\u6E05\u6670\u8BA4\u8BC6\u3002</p><p>\u5168\u5C40\u6CD5\u4F7F\u7528\u7279\u5B9A\u63AA\u65BD\u9010\u6B65\u589E\u5F3A\u5B89\u5168\uFF0C\u52A9\u529B\u9632\u62A4\u5DE5\u63A7\u7CFB\u7EDF\u4E2D\u7684\u7F51\u7EDC\u5B89\u5168\u5A01\u80C1\u4E0E\u6F0F\u6D1E\u3002\u8FD9\u79CD\u65B9\u6CD5\u4E00\u822C\u88AB\u79F0\u4E3A\u201C\u7EB5\u6DF1\u9632\u5FA1\u201D\uFF0C\u9002\u7528\u4E8E\u5DE5\u63A7\u7CFB\u7EDF\uFF0C\u4E3A\u4F18\u5316\u7F51\u7EDC\u5B89\u5168\u9632\u62A4\u63D0\u4F9B\u4E86\u7075\u6D3B\u3001\u53EF\u7528\u7684\u6846\u67B6\u3002</p><p>\u4EBA\u4EEC\u4E4B\u6240\u4EE5\u5173\u6CE8\u63A7\u5236\u7CFB\u7EDF\u7684\u7F51\u7EDC\u5B89\u5168\u95EE\u9898\uFF0C\u4E00\u65B9\u9762\u662F\u56E0\u4E3A\u67D0\u4E9B\u7CFB\u7EDF\u6CBF\u7528\u4F20\u7EDF\u7279\u6027\uFF0C\u53E6\u4E00\u65B9\u9762\u662F\u56E0\u4E3A\u5DE5\u63A7\u7CFB\u7EDF\u8054\u7F51\u9700\u6C42\u65E5\u76CA\u589E\u957F\u3002</p><p>\u5728\u8FD9\u79CD\u5173\u6CE8\u4E0B\uFF0C\u5927\u91CF\u5DF2\u77E5\u6F0F\u6D1E\u88AB\u53D1\u73B0\uFF0C\u540C\u65F6\u4E00\u4E9B\u5DE5\u63A7\u7CFB\u7EDF\u9886\u57DF\u524D\u6240\u672A\u89C1\u7684\u65B0\u578B\u5A01\u80C1\u4E5F\u6D6E\u51FA\u6C34\u9762\u3002</p><p>\u8BB8\u591A\u8001\u65E7\u7CFB\u7EDF\u7F3A\u4E4F\u6070\u5F53\u7684\u5B89\u9632\u80FD\u529B\uFF0C\u65E0\u6CD5\u62B5\u5FA1\u65B0\u578B\u5A01\u80C1\uFF0C\u800C\u73B0\u884C\u7F51\u7EDC\u5B89\u5168\u65B9\u6848\u7531\u4E8E\u4F1A\u5F71\u54CD\u5230\u7CFB\u7EDF\u53EF\u7528\u6027\u800C\u65E0\u6CD5\u4F7F\u7528\u3002</p><p>\u5DE5\u63A7\u7CFB\u7EDF\u8FDE\u63A5\u5230\u4F01\u4E1A\u3001\u5382\u5546\u6216\u5BF9\u7B49\u7F51\u7EDC\u53EF\u52A0\u5267\u6B64\u95EE\u9898\u3002</p><h2 id="\u73B0\u884C\u5DE5\u63A7\u7CFB\u7EDF\u67B6\u6784\u6982\u89C8" tabindex="-1"><a class="header-anchor" href="#\u73B0\u884C\u5DE5\u63A7\u7CFB\u7EDF\u67B6\u6784\u6982\u89C8" aria-hidden="true">#</a> \u73B0\u884C\u5DE5\u63A7\u7CFB\u7EDF\u67B6\u6784\u6982\u89C8</h2><p>\u66FE\u7ECF\u9694\u79BB\u7684\u5DE5\u63A7\u7CFB\u7EDF\u9010\u6E10\u8D70\u5411\u878D\u5408\uFF0C\u52A9\u529B\u4F01\u4E1A\u7B80\u5316\u5E76\u7BA1\u7406\u590D\u6742\u7684\u73AF\u5883\u3002\u5728\u8054\u7F51\u53CA\u5411\u5DE5\u63A7\u7CFB\u7EDF\u57DF\u6DFB\u52A0 IT \u7EC4\u4EF6\u65F6\uFF0C\u5982\u4E0B\u60C5\u51B5\u53EF\u5BFC\u81F4\u5B89\u5168\u95EE\u9898\uFF1A</p><ul><li><p>\u5BF9\u4E8E\u81EA\u52A8\u5316\u4E0E\u5DE5\u63A7\u7CFB\u7EDF\u8D8A\u6765\u8D8A\u4F9D\u8D56\uFF1B</p></li><li><p>\u4E0E\u5916\u90E8\u7F51\u7EDC\u7684\u4E0D\u5B89\u5168\u8FDE\u63A5\uFF1B</p></li><li><p>\u4F7F\u7528\u7684\u6280\u672F\u5305\u542B\u5DF2\u77E5\u6F0F\u6D1E\uFF0C\u5728\u63A7\u5236\u57DF\u9020\u6210\u524D\u6240\u672A\u89C1\u7684\u7F51\u7EDC\u98CE\u9669\uFF1B</p></li><li><p>\u7F3A\u4E4F\u4E0E\u5DE5\u63A7\u7CFB\u7EDF\u73AF\u5883\u76F8\u5173\u7684\u7F51\u7EDC\u5B89\u5168\u4E1A\u52A1\u6848\u4F8B\uFF1B</p></li><li><p>\u67D0\u4E9B\u63A7\u5236\u7CFB\u7EDF\u6280\u672F\u4EC5\u6709\u6709\u9650\u7684\u5B89\u5168\u80FD\u529B\uFF0C\u8FD9\u79CD\u80FD\u529B\u4E00\u822C\u4EC5\u5728\u7BA1\u7406\u5458\u53D1\u73B0\uFF08\u6216\u4E0D\u4F1A\u963B\u788D\u6D41\u7A0B\uFF09\u65F6\u624D\u4F1A\u542F\u7528\uFF1B</p></li><li><p>\u8BB8\u591A\u5E38\u7528\u7684\u63A7\u5236\u7CFB\u7EDF\u901A\u4FE1\u534F\u8BAE\u7F3A\u4E4F\u57FA\u672C\u7684\u5B89\u5168\u529F\u80FD\uFF08\u5982\u8BA4\u8BC1\u4E0E\u6388\u6743\uFF09\uFF1B</p></li><li><p>\u5173\u4E8E\u5DE5\u63A7\u7CFB\u7EDF\u3001\u5DE5\u63A7\u7CFB\u7EDF\u64CD\u4F5C\u53CA\u5B89\u5168\u6F0F\u6D1E\u7684\u5F00\u6E90\u4FE1\u606F\u5927\u91CF\u5B58\u5728<sup class="footnote-ref"><a href="#footnote1">[1]</a><a class="footnote-anchor" id="footnote-ref1"></a></sup>\u3002</p></li></ul><p>\u957F\u671F\u4EE5\u6765\uFF0C\u4E1A\u754C\u5C06\u63A7\u5236\u7CFB\u7EDF\u7684\u8FD0\u8425\u5B89\u5168\u5B9A\u4E49\u4E3A\u7CFB\u7EDF\u5B89\u5168\u6709\u6548\u8FD0\u884C\u7684\u53EF\u9760\u6027\u6C34\u5E73\u3002\u5C06\u5DE5\u63A7\u7CFB\u7EDF\u540C\u5916\u90E8\uFF08\u4E0D\u53EF\u4FE1\uFF09\u7F51\u7EDC\u5B8C\u5168\u9694\u79BB\uFF0C\u603B\u4F53\u901A\u4FE1\u5B89\u5168\u7684\u8303\u56F4\u88AB\u538B\u7F29\u81F3\u5458\u5DE5\u76F8\u5173\u5A01\u80C1\uFF08\u8FD9\u91CC\u7684\u5458\u5DE5\u6307\u7684\u662F\u53EF\u7269\u7406\u8BBF\u95EE\u8BBE\u5907\u6216\u5DE5\u5382\u8F66\u95F4\u7684\u5458\u5DE5\uFF09\u3002\u8FD9\u6837\uFF0C\u4FE1\u606F\u57FA\u7840\u8BBE\u65BD\u5185\u7684\u5927\u591A\u6570\u6570\u636E\u901A\u4FE1\u4EC5\u9700\u8981\u6709\u9650\u6388\u6743\u6216\u5B89\u5168\u76D1\u7BA1\u3002\u8FD0\u884C\u547D\u4EE4\u3001\u6307\u4EE4\u4E0E\u6570\u636E\u91C7\u96C6\u53D1\u751F\u5728\u5C01\u95ED\u73AF\u5883\u4E2D\uFF0C\u8FD9\u4E2A\u73AF\u5883\u4E2D\u7684\u6240\u6709\u901A\u4FE1\u90FD\u53D7\u4FE1\u4EFB\u3002\u4E00\u822C\u60C5\u51B5\u4E0B\uFF0C\u547D\u4EE4\u6216\u6307\u4EE4\u901A\u8FC7\u7F51\u7EDC\u4E0B\u53D1\uFF0C\u9884\u671F\u5728\u5230\u8FBE\u76EE\u6807\u540E\u6267\u884C\u6388\u6743\u529F\u80FD\uFF0C\u56E0\u4E3A\u53EA\u6709\u6388\u6743\u64CD\u4F5C\u5458\u624D\u53EF\u4EE5\u8BBF\u95EE\u7CFB\u7EDF\u3002</p><h2 id="\u5DE5\u63A7\u7CFB\u7EDF\u5185\u7684\u5B89\u5168\u6311\u6218" tabindex="-1"><a class="header-anchor" href="#\u5DE5\u63A7\u7CFB\u7EDF\u5185\u7684\u5B89\u5168\u6311\u6218" aria-hidden="true">#</a> \u5DE5\u63A7\u7CFB\u7EDF\u5185\u7684\u5B89\u5168\u6311\u6218</h2><p>\u5728\u57FA\u4E8E\u4F20\u8F93\u63A7\u5236\u534F\u8BAE/\u4E92\u8054\u7F51\u534F\u8BAE\uFF08TCP/IP\uFF09\u7684\u73B0\u4EE3\u8BA1\u7B97\u73AF\u5883\u4E2D\uFF08\u5982\u5BF9\u9A71\u52A8\u63A7\u5236\u7CFB\u7EDF\u8FD0\u884C\u7684\u4E1A\u52A1\u8FDB\u884C\u7BA1\u7406\u7684\u4F01\u4E1A\u57FA\u7840\u8BBE\u65BD\uFF09\uFF0C\u9700\u89E3\u51B3\u6280\u672F\u76F8\u5173\u6F0F\u6D1E\u95EE\u9898\u3002\u4F20\u7EDF\u4E0A\uFF0C\u8FD9\u4E9B\u95EE\u9898\u7531\u4F01\u4E1A\u7684IT\u5B89\u5168\u7EC4\u7EC7\u8D1F\u8D23\uFF0C\u6839\u636E\u91CD\u8981\u4FE1\u606F\u8D44\u4EA7\u7684\u5B89\u5168\u6307\u5BFC\u65B9\u6848\u4E0E\u8FD0\u8425\u8BA1\u5212\u8FDB\u884C\u5DE5\u4F5C\u3002\u5F53\u5DE5\u63A7\u7CFB\u7EDF\u4ECE\u5C5E\u4E8E\u8054\u52A8\u67B6\u6784\u65F6\uFF0C\u4E3B\u8981\u5173\u6CE8\u7684\u95EE\u9898\u5C31\u53D8\u6210\u5982\u4F55\u63D0\u4F9B\u540C\u65F6\u8986\u76D6\u63A7\u5236\u7CFB\u7EDF\u57DF\u7684\u5B89\u5168\u89C4\u7A0B\u3002\u73B0\u6709\u57FA\u4E8E\u7F51\u7EDC\u7684\u901A\u4FE1\u6240\u4EA7\u751F\u7684\u67D0\u4E9B\u5B89\u5168\u95EE\u9898\u987B\u5728\u63A7\u5236\u7CFB\u7EDF\u57DF\u89E3\u51B3\uFF0C\u56E0\u4E3A\u5404\u5382\u5546\u4F7F\u7528\u4E0D\u540C\u534F\u8BAE\uFF0C\u518D\u52A0\u4E0A\u8001\u65E7\u7CFB\u7EDF\u56FA\u6709\u7684\u5B89\u5168\u95EE\u9898\uFF0C\u4E5F\u8BB8\u5F88\u96BE\u4FDD\u62A4\u5173\u952E\u4E1A\u52A1\u7CFB\u7EDF\u514D\u4E8E\u906D\u53D7\u65F6\u4E0B\u7684\u7F51\u7EDC\u653B\u51FB\u3002</p><p>\u5F00\u653E\u7684\u7CFB\u7EDF\u67B6\u6784\u4E2D\u5B58\u5728\u7684\u3001\u53EF\u8FC1\u79FB\u81F3\u63A7\u5236\u7CFB\u7EDF\u57DF\u7684\u6F0F\u6D1E\u5305\u62EC\u6076\u610F\u8F6F\u4EF6\uFF08\u75C5\u6BD2\u3001\u8815\u866B\u7B49\u7B49\uFF09\u6F0F\u6D1E\u3001\u901A\u8FC7\u64CD\u63A7\u4EE3\u7801\u63D0\u6743\u3001\u7F51\u7EDC\u4FA6\u6D4B\u4E0E\u6570\u636E\u6536\u96C6\u3001\u9690\u853D\u6D41\u91CF\u5206\u6790\u3001\u901A\u8FC7\u6216\u7ED5\u8FC7\u8FB9\u754C\u9632\u62A4\u975E\u6CD5\u5165\u4FB5\u7F51\u7EDC\u7B49\u3002\u5BF9\u4E8E\u66F4\u4E3A\u5148\u8FDB\u7684\u7CFB\u7EDF\uFF0C\u6F0F\u6D1E\u8FD8\u5305\u62EC\u6076\u610F\u79FB\u52A8\u4EE3\u7801\uFF0C\u5982\u6D89\u53CA JavaScript\u3001applet \u5C0F\u7A0B\u5E8F\u3001VBScript \u53CA ActiveX \u7684\u6076\u610F\u6D3B\u52A8\u5185\u5BB9\u3002\u6210\u529F\u5165\u4FB5\u5DE5\u63A7\u7CFB\u7EDF\u7F51\u7EDC\u540E\uFF0C\u4F1A\u51FA\u73B0\u65B0\u7684\u95EE\u9898\uFF0C\u5982\u63A7\u5236\u7CFB\u7EDF\u534F\u8BAE\u53CD\u5411\u5DE5\u7A0B\u3001\u9488\u5BF9\u64CD\u4F5C\u5458\u63A7\u5236\u53F0\u7684\u653B\u51FB\u3001\u975E\u6CD5\u8BBF\u95EE\u53D7\u4FE1\u4EFB\u7684\u5BF9\u7AEF\u7F51\u7EDC\u4E0E\u8FDC\u7A0B\u8BBE\u65BD\u7B49\u3002\u8981\u5C06\u4FE1\u606F\u5B89\u5168\u4E0E\u4FE1\u606F\u4FDD\u969C\u5B8C\u5168\u5F15\u5165\u63A7\u5236\u7CFB\u7EDF\u57DF\uFF0C\u5FC5\u987B\u4E86\u89E3\u4F20\u7EDF IT \u67B6\u6784\u4E0E\u5DE5\u63A7\u7CFB\u7EDF\u6280\u672F\u4E4B\u95F4\u7684\u5173\u952E\u5DEE\u5F02\u3002</p><h2 id="\u5DE5\u63A7\u7CFB\u7EDF\u7684\u4E94\u4E2A\u5173\u952E\u7684\u5B89\u5168\u63AA\u65BD" tabindex="-1"><a class="header-anchor" href="#\u5DE5\u63A7\u7CFB\u7EDF\u7684\u4E94\u4E2A\u5173\u952E\u7684\u5B89\u5168\u63AA\u65BD" aria-hidden="true">#</a> \u5DE5\u63A7\u7CFB\u7EDF\u7684\u4E94\u4E2A\u5173\u952E\u7684\u5B89\u5168\u63AA\u65BD</h2><p>\u4EE5\u4E0B\u662F\u4E94\u4E2A\u5173\u952E\u7684\u5B89\u5168\u63AA\u65BD\uFF0C\u53EF\u63A8\u52A8\u5DE5\u63A7\u7CFB\u7EDF\u73AF\u5883\u4E2D\u7684\u7F51\u7EDC\u5B89\u5168\u6D3B\u52A8\u3002</p><ul><li><p>\u5B89\u5168\u6307\u5BFC\u65B9\u6848\u3002\u5E94\u9488\u5BF9\u63A7\u5236\u7CFB\u7EDF\u53CA\u5176\u5404\u90E8\u4EF6\u5236\u5B9A\u5B89\u5168\u6307\u5BFC\u65B9\u6848\uFF0C\u5B9A\u671F\u8BC4\u5BA1\uFF0C\u4EE5\u4FBF\u7EB3\u5165\u5F53\u524D\u5A01\u80C1\u73AF\u5883\u3001\u7CFB\u7EDF\u529F\u80FD\u4EE5\u53CA\u6240\u9700\u7684\u5B89\u5168\u7EA7\u522B\u3002</p></li><li><p>\u963B\u6B62\u5BF9\u8D44\u6E90\u548C\u670D\u52A1\u7684\u8BBF\u95EE\u3002\u4E00\u822C\u60C5\u51B5\u4E0B\uFF0C\u5728\u7F51\u7EDC\u4E2D\u90E8\u7F72\u63D0\u4F9B\u8BBF\u95EE\u63A7\u5236\u5217\u8868\u7684<strong>\u8FB9\u754C\u8BBE\u5907</strong>\u5982\u9632\u706B\u5899\u6216\u4EE3\u7406\u670D\u52A1\u5668\uFF0C\u63D0\u4F9B\u8BE5\u6280\u672F\u3002\u800C\u4E3B\u901A\u8FC7\u673A\u65B9\u9762\uFF0C\u8BE5\u6280\u672F\u53EF\u90E8\u7F72<strong>\u57FA\u4E8E\u4E3B\u673A</strong>\u7684\u9632\u706B\u5899\u548C\u6740\u6BD2\u8F6F\u4EF6\u5B9E\u73B0\u3002</p></li><li><p>\u68C0\u6D4B\u6076\u610F\u6D3B\u52A8\u3002\u6076\u610F\u6D3B\u52A8\u68C0\u6D4B\u53EF\u5728\u7F51\u7EDC\u6216\u4E3B\u673A\u5C42\u9762\u5B9E\u73B0\uFF0C\u901A\u5E38\u9700\u6709\u7ECF\u9A8C\u7684\u7BA1\u7406\u5458\u5BF9\u65E5\u5FD7\u6587\u4EF6\u5B9A\u671F\u76D1\u63A7\u3002IDS \u662F\u8BC6\u522B\u7F51\u7EDC\u95EE\u9898\u7684\u5E38\u7528\u624B\u6BB5\uFF0C\u4E5F\u53EF\u90E8\u7F72\u5728\u5355\u4E2A\u4E3B\u673A\u4E0A\u3002\u5C3D\u91CF\u5728\u4E3B\u673A\u4E0A\u5F00\u542F\u5BA1\u8BA1\u548C\u4E8B\u4EF6\u65E5\u5FD7\u529F\u80FD\u3002</p></li><li><p>\u7F13\u89E3\u53EF\u80FD\u51FA\u73B0\u7684\u653B\u51FB\u3002\u5728\u5F88\u591A\u60C5\u51B5\u4E0B\uFF0C\u65E0\u9700\u5904\u7406\u6F0F\u6D1E\uFF0C\u56E0\u4E3A\u6F0F\u6D1E\u4FEE\u590D\u53EF\u80FD\u4F1A\u4F7F\u7CFB\u7EDF\u4E0D\u53EF\u7528\u6216\u6548\u7387\u964D\u4F4E\u3002\u901A\u8FC7\u7F13\u89E3\u63AA\u65BD\uFF0C\u7BA1\u7406\u5458\u53EF\u63A7\u5236\u5BF9\u6F0F\u6D1E\u7684\u8BBF\u95EE\uFF0C\u786E\u4FDD\u6F0F\u6D1E\u4E0D\u88AB\u5229\u7528\u3002\u901A\u5E38\uFF0C\u8FD9\u4E00\u60C5\u51B5\u5728\u5236\u5B9A\u4E34\u65F6\u6280\u672F\u65B9\u6848\uFF0C\u521B\u5EFA\u8FC7\u6EE4\u5668\u6216\u8FD0\u884C\u5177\u5907\u7279\u5B9A\u914D\u7F6E\u7684\u670D\u52A1\u548C\u5E94\u7528\u65F6\u975E\u5E38\u5FC5\u8981\u3002</p></li><li><p>\u89E3\u51B3\u6838\u5FC3\u95EE\u9898\u3002\u8981\u89E3\u51B3\u6838\u5FC3\u5B89\u5168\u95EE\u9898\uFF0C\u9700\u7ECF\u5E38\u66F4\u65B0\u3001\u5347\u7EA7\u3001\u5B89\u88C5\u8F6F\u4EF6\u6F0F\u6D1E\u8865\u4E01\u6216\u79FB\u9664\u6709\u6F0F\u6D1E\u7684\u5E94\u7528\u3002\u8F6F\u4EF6\u6F0F\u6D1E\u53EF\u80FD\u4F1A\u5B58\u5728\u4E8E\u7F51\u7EDC\u3001\u64CD\u4F5C\u7CFB\u7EDF\u6216\u5E94\u7528\u8FD9\u4E09\u5C42\u4E2D\u7684\u4EFB\u4E00\u5C42\u3002\u5382\u5546\u6216\u5F00\u53D1\u4EBA\u5458\u5E94\u63D0\u4F9B\u7F13\u89E3\u63AA\u65BD\uFF08\u5982\u679C\u6709\u7684\u8BDD\uFF09\u4F9B\u7BA1\u7406\u5458\u90E8\u7F72\u3002</p></li></ul><blockquote><p>\u539F\u6587\u540D\u79F0\uFF1A<br> Recommended Practice: Improving Industrial Control Systems Cybersecurity with Defense-In-Depth Strategies</p></blockquote><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="footnote1" class="footnote-item"><p>\u5BF9\u4E8E\u6709\u6548\u4FDD\u969C\u7F51\u7EDC\u4E0E IT \u7F51\u7EDC\u5B89\u5168\uFF0C\u8FD9\u79CD\u65B9\u6CD5\u53EF\u8C13\u53E6\u8F9F\u8E4A\u5F84\u3002\u5C06\u65B0\u578B IT \u67B6\u6784\u4E0E\u7F3A\u4E4F\u771F\u6B63\u7F51\u7EDC\u5B89\u5168\u9632\u62A4\u63AA\u65BD\u7684\u9694\u79BB\u7F51\u7EDC\u878D\u5408\u5177\u6709\u5F88\u5927\u6311\u6218\u3002\u663E\u7136\uFF0C\u4F7F\u7528\u8DEF\u7531\u5668\u4E0E\u4EA4\u6362\u673A\u53EF\u5C06\u8BBE\u5907\u8FDB\u884C\u7B80\u5355\u4E92\u8054\uFF0C\u4F46\u662F\u4E2A\u4EBA\u7684\u975E\u6CD5\u5165\u4FB5\u4F1A\u5BFC\u81F4\u5BF9\u7CFB\u7EDF\u7684\u4E0D\u53D7\u9650\u8BBF\u95EE\u3002 <a href="#footnote-ref1" class="footnote-backref">\u21A9\uFE0E</a></p></li></ol></section>',21);function i(a,s){return o}var r=e(p,[["render",i]]);export{r as default};
